def _construct_synthesis_table(verified_text: str) -> str:
    """Build a `Finding | Value | Source` table BY CONSTRUCTION from the verified prose. Each row's
    Value is a verbatim value+unit span of ONE verified sentence, Source is that sentence's own [N]
    marker(s), and Finding is that sentence minus its markers. Rows group by comparable unit; the table
    is emitted only when >=2 rows share one unit key (comparison EMERGES from the data). NEVER calls an
    LLM, NEVER drops/alters prose (a sentence with no value+unit simply is not a source row)."""
    groups: "dict[str, list[tuple[str, str, str]]]" = {}
    order: list[str] = []
    for sent in split_into_sentences(verified_text):
        markers = _CANON_MARKER_RE.findall(sent)
        if not markers:
            continue
        m = _CONSTRUCT_VALUE_UNIT_RE.search(sent)
        if not m:
            continue
        unit_key = _construct_unit_key(m.group(1))
        if not unit_key:
            continue
        value = _construct_table_cell(m.group(0))            # verbatim value+unit span
        finding = _construct_table_cell(_CANON_MARKER_RE.sub("", sent))  # sentence minus its own [N]s
        source = "".join(sorted(set(markers), key=lambda s: int(s[1:-1])))
        if unit_key not in groups:
            groups[unit_key] = []
            order.append(unit_key)
        groups[unit_key].append((finding, value, source))
    best = max((groups[k] for k in order if len(groups[k]) >= 2), key=len, default=None)
    if not best:
        return ""
    lines = ["| Finding | Value | Source |", "|---|---|---|"]
    for finding, value, source in best:
        lines.append(f"| {finding} | {value} | {source} |")
    return "\n".join(lines)

